(lib.titleMc = function(mode,startPosition,loop) {
	this.initialize(mode,startPosition,loop,{});

	// timeline functions:
	this.frame_0 = function() {
		this.stop();
	}
	this.frame_24 = function() {
		this.stop();
		var m = this;
		setTimeout(function(){m.play()}, 1000);
	}
	this.frame_25 = function() {
		playSound("startShoot");
	}
	this.frame_49 = function() {
		stage.dispatchEvent("footShoot");
	}

	// actions tween:
	this.timeline.addTween(cjs.Tween.get(this).call(this.frame_0).wait(24).call(this.frame_24).wait(1).call(this.frame_25).wait(24).call(this.frame_49).wait(1));

	// 图层 1
	this.title = new lib.titleShape();
	this.title.setTransform(-525.5,67,1,1,0,0,0,114.5,67);

	this.timeline.addTween(cjs.Tween.get(this.title).to({x:244.5},24,cjs.Ease.get(1)).to({x:908.5},25,cjs.Ease.get(-0.5)).wait(1));

}).prototype = p = new cjs.MovieClip();
p.nominalBounds = new cjs.Rectangle(-789,-9,521,166);


